elements.content:
flowchart LR
  U[You] --> APP[Client App]
  APP --> GW[API Gateway]
  GW --> ORCH[Orchestrator]

  classDef default fill:#1f2937,stroke:#64748b,color:#f8fafc,stroke-width:1px;
  classDef focus fill:#fb923c,stroke:#fed7aa,color:#111827,stroke-width:3px;
  classDef dim fill:#111827,stroke:#334155,color:#94a3b8;
  class GW focus;
  class U,APP,ORCH dim;

flowchart LR
  APP[Client App] --> GW[API Gateway]
  GW --> AUTH[Identity Check]
  GW --> RATE[Rate Limit]
  AUTH --> ROUTE[Routing Logic]
  RATE --> ROUTE
  ROUTE --> ORCH[Orchestrator]

  classDef default fill:#1f2937,stroke:#64748b,color:#f8fafc,stroke-width:1px;
  classDef focus fill:#22d3ee,stroke:#a5f3fc,color:#0f172a,stroke-width:3px;
  classDef orange fill:#fb923c,stroke:#fed7aa,color:#111827,stroke-width:3px;
  classDef dim fill:#111827,stroke:#334155,color:#94a3b8;
  class GW orange;
  class AUTH,RATE,ROUTE focus;
  class APP,ORCH dim;

flowchart LR
  ORCH[Orchestrator] --> POLICY[Policy Engine]
  POLICY -->|Approved| CTX[Context Builder]
  POLICY -->|Flagged| REVIEW[Safe Handling]

  classDef default fill:#1f2937,stroke:#64748b,color:#f8fafc,stroke-width:1px;
  classDef safety fill:#10b981,stroke:#bbf7d0,color:#052e16,stroke-width:3px;
  classDef warn fill:#ef4444,stroke:#fecaca,color:#111827,stroke-width:3px;
  classDef dim fill:#111827,stroke:#334155,color:#94a3b8;
  class POLICY safety;
  class REVIEW warn;
  class ORCH,CTX dim;

flowchart LR
  MSG[Your Message] --> CTX[Context Builder]
  SYS[System Instructions] --> CTX
  HIST[Chat History] --> CTX
  CTX --> PACK[Final Prompt Package]
  PACK --> MODEL[Model Server]

  classDef default fill:#1f2937,stroke:#64748b,color:#f8fafc,stroke-width:1px;
  classDef focus fill:#a78bfa,stroke:#ddd6fe,color:#111827,stroke-width:3px;
  classDef source fill:#334155,stroke:#94a3b8,color:#f8fafc,stroke-width:2px;
  classDef dim fill:#111827,stroke:#334155,color:#94a3b8;
  class CTX,PACK focus;
  class MSG,SYS,HIST source;
  class MODEL dim;

flowchart LR
  PACK[Prompt Package] --> TOK[Tokenizer]
  TOK --> MODEL[Model Server]
  MODEL --> GPU[GPU Cluster]
  GPU --> GEN[Token Generator]

  classDef default fill:#1f2937,stroke:#64748b,color:#f8fafc,stroke-width:1px;
  classDef compute fill:#f97316,stroke:#fed7aa,color:#111827,stroke-width:3px;
  classDef cyan fill:#22d3ee,stroke:#a5f3fc,color:#0f172a,stroke-width:3px;
  classDef dim fill:#111827,stroke:#334155,color:#94a3b8;
  class TOK cyan;
  class MODEL,GPU,GEN compute;
  class PACK dim;

flowchart RL
  GEN[Token Generator] --> MODEL[Model Server]
  MODEL --> ORCH[Orchestrator]
  ORCH --> GW[API Gateway]
  GW --> APP[Client App]
  APP --> U[You]

  classDef default fill:#1f2937,stroke:#64748b,color:#f8fafc,stroke-width:1px;
  classDef stream fill:#22d3ee,stroke:#a5f3fc,color:#0f172a,stroke-width:3px;
  classDef focus fill:#fb923c,stroke:#fed7aa,color:#111827,stroke-width:3px;
  classDef dim fill:#111827,stroke:#334155,color:#94a3b8;
  class GEN,MODEL,ORCH,GW,APP stream;
  class U focus;

flowchart LR
  GEN[Generated Text] --> OUTSAFE[Output Safety Pass]
  OUTSAFE -->|Clear| FMT[Formatter]
  OUTSAFE -->|Needs handling| SAFE[Safe Response]

  classDef default fill:#1f2937,stroke:#64748b,color:#f8fafc,stroke-width:1px;
  classDef safety fill:#10b981,stroke:#bbf7d0,color:#052e16,stroke-width:3px;
  classDef warn fill:#ef4444,stroke:#fecaca,color:#111827,stroke-width:3px;
  classDef dim fill:#111827,stroke:#334155,color:#94a3b8;
  class OUTSAFE safety;
  class SAFE warn;
  class GEN,FMT dim;

flowchart LR
  RAW[Raw Answer] --> FMT[Formatter]
  FMT --> TEXT[Readable Text]
  FMT --> CODE[Code Block]
  FMT --> CITE[Citations]
  TEXT --> FINAL[Final Message]
  CODE --> FINAL
  CITE --> FINAL

  classDef default fill:#1f2937,stroke:#64748b,color:#f8fafc,stroke-width:1px;
  classDef format fill:#a78bfa,stroke:#ddd6fe,color:#111827,stroke-width:3px;
  classDef output fill:#22d3ee,stroke:#a5f3fc,color:#0f172a,stroke-width:3px;
  classDef dim fill:#111827,stroke:#334155,color:#94a3b8;
  class FMT format;
  class TEXT,CODE,CITE,FINAL output;
  class RAW dim;

flowchart LR
  FINAL[Final Message] --> GW[API Gateway]
  GW --> APP[Client App]
  APP --> U[You]
  GW --> LOG[Logging]
  GW --> METRICS[Telemetry]
  METRICS --> LAT[Latency]
  METRICS --> TPS[Throughput]

  classDef default fill:#1f2937,stroke:#64748b,color:#f8fafc,stroke-width:1px;
  classDef delivery fill:#fb923c,stroke:#fed7aa,color:#111827,stroke-width:3px;
  classDef observe fill:#22d3ee,stroke:#a5f3fc,color:#0f172a,stroke-width:3px;
  classDef dim fill:#111827,stroke:#334155,color:#94a3b8;
  class FINAL,GW,APP,U delivery;
  class LOG,METRICS,LAT,TPS observe;
